using namespace std;
typedef long long ll;

ll modpow(ll base, ll exp, ll mod) {
    ll result = 1 % mod;
    base %= mod;
    while(exp &gt; 0){
        if(exp &amp; 1)
            result = (result * base) % mod;
        base = (base * base) % mod;
        exp &gt;&gt;= 1;
    }
    return result;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    ll M;
    cin &gt;&gt; N &gt;&gt; M;

    vector&lt;int&gt; divs;
    // Find all divisors of N
    for (int i = 1; i * i &lt;= N; i++){
        if(N % i == 0) {
            divs.push_back(i);
            if(i != N / i)
                divs.push_back(N / i);
        }
    }
    sort(divs.begin(), divs.end());

    unordered_map&lt;int, ll&gt; dp; // dp[d] stores a(d): count of primitive strings of length d mod M
    for (int d : divs) {
        ll total = modpow(2, d, M);
        // Subtract contributions from all proper divisors of d
        for (int x : divs) {
            if (x &gt;= d)
                break;
            if(d % x == 0) {
                total = (total - dp[x] + M) % M;
            }
        }
        dp[d] = total;
    }
    cout &lt;&lt; dp[N] % M &lt;&lt; "\n";
    return 0;
}
